public CompletableFuture<Void> processSaga(Order order) {
    return CompletableFuture.supplyAsync(() -> paymentClient.charge(order), customExecutor)
        .thenApplyAsync(result -> inventoryClient.reserve(result)) 
        .exceptionally(ex -> {
            compensate(order);
            return null;
        });
